CREATE DEFINER=`root`@`localhost` PROCEDURE `generate_5000_transaksi_only` ()   BEGIN
  DECLARE i INT DEFAULT 1;
  DECLARE random_pembeli INT;
  DECLARE random_alamat INT;
  DECLARE random_produk INT;
  DECLARE jumlah_item INT;
  DECLARE harga_produk DECIMAL(12,2);
  DECLARE subtotal_item DECIMAL(12,2);
  DECLARE total_transaksi DECIMAL(12,2);
  DECLARE item_loop INT;
  DECLARE new_pesanan_id INT;

  DECLARE min_pembeli INT;
  DECLARE max_pembeli INT;
  DECLARE min_produk INT;
  DECLARE max_produk INT;

  -- Ambil range ID yang tersedia
  SELECT MIN(id_pembeli), MAX(id_pembeli) INTO min_pembeli, max_pembeli FROM Pembeli;
  SELECT MIN(id_produk), MAX(id_produk) INTO min_produk, max_produk FROM Produk;

  WHILE i <= 5000 DO

    SET random_pembeli = FLOOR(min_pembeli + RAND() * (max_pembeli - min_pembeli + 1));

    -- Ambil alamat milik pembeli tersebut
    SELECT id_alamat INTO random_alamat
    FROM Alamat
    WHERE id_pembeli = random_pembeli
    ORDER BY RAND()
    LIMIT 1;

    SET total_transaksi = 0;

      id_pembeli,
      id_alamat,
      total_harga,
      status_pesanan,
      kode_invoice
    ) VALUES (
      random_pembeli,
      random_alamat,
      0,
      ELT(FLOOR(1+RAND()*4),'pending','diproses','dikirim','selesai'),
      CONCAT('INV',UUID())
    );

    SET new_pesanan_id = LAST_INSERT_ID();

    SET item_loop = FLOOR(1 + RAND()*3); -- 1-3 produk per pesanan

    WHILE item_loop > 0 DO

      SET random_produk = FLOOR(min_produk + RAND() * (max_produk - min_produk + 1));
      SET jumlah_item = FLOOR(1 + RAND()*3);

      SELECT harga INTO harga_produk
      FROM Produk
      WHERE id_produk = random_produk;

      SET subtotal_item = harga_produk * jumlah_item;
      SET total_transaksi = total_transaksi + subtotal_item;

        id_pesanan,
        id_produk,
        jumlah,
        harga_satuan,
        subtotal
      ) VALUES (
        new_pesanan_id,
        random_produk,
        jumlah_item,
        harga_produk,
        subtotal_item
      );

      SET item_loop = item_loop - 1;

    END WHILE;

    UPDATE Pesanan
    SET total_harga = total_transaksi
    WHERE id_pesanan = new_pesanan_id;

      id_pesanan,
      id_metode,
      tanggal_bayar,
      jumlah_bayar,
      status_pembayaran
    ) VALUES (
      new_pesanan_id,
      (SELECT id_metode FROM Metode_Pembayaran ORDER BY RAND() LIMIT 1),
      NOW(),
      total_transaksi,
      ELT(FLOOR(1+RAND()*3),'pending','lunas','gagal')
    );

      id_pesanan,
      id_produk,
      id_pembeli,
      rating,
      komentar
    ) VALUES (
      new_pesanan_id,
      (SELECT id_produk FROM Detail_Pesanan WHERE id_pesanan = new_pesanan_id LIMIT 1),
      random_pembeli,
      FLOOR(3 + RAND()*3),
      ELT(FLOOR(1+RAND()*5),
        'Barang bagus dan original',
        'Packing rapi dan aman',
        'Pengiriman cepat sekali',
        'Sesuai deskripsi',
        'Recommended seller terpercaya'
      )
    );

    SET i = i + 1;

  END WHILE;

END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `generate_pembeli_alamat` ()   BEGIN
  DECLARE i INT DEFAULT 1;
  DECLARE nama_depan VARCHAR(50);
  DECLARE nama_belakang VARCHAR(50);

  WHILE i <= 5000 DO

    SET nama_depan = ELT(FLOOR(1+RAND()*15),'Ariel','Riel','Idan','Ijul','Raffi','Zaki','Gita','Mima','Uqi','Habiba','Firda','Lutfi','Mega','Nanda','Rizky');
    SET nama_belakang = ELT(FLOOR(1+RAND()*15),'Prasetyo','Saputri','Wijaya','Putra','Lestari','Ramadhan','Nugraha','Permata','Santoso','Kurniawan','Maulana','Purnama','Utami','Hidayat','Ananda');

    VALUES (
      CONCAT(nama_depan,' ',nama_belakang),
      CONCAT('user',i,'@mail.com'),
      '123456',
      CONCAT('08',FLOOR(100000000 + RAND()*899999999)),
      'aktif'
    );

      id_pembeli,nama_penerima,no_hp,alamat_lengkap,kota,provinsi,kode_pos,status_default
    ) VALUES (
      i,
      CONCAT(nama_depan,' ',nama_belakang),
      CONCAT('08',FLOOR(100000000 + RAND()*899999999)),
      CONCAT('Jl. Melati No.',FLOOR(1+RAND()*200)),
      ELT(FLOOR(1+RAND()*5),'Surabaya','Malang','Jakarta','Bandung','Yogyakarta'),
      ELT(FLOOR(1+RAND()*5),'Jawa Timur','DKI Jakarta','Jawa Barat','DI Yogyakarta','Jawa Tengah'),
      FLOOR(10000 + RAND()*89999),
      TRUE
    );

    SET i = i + 1;
  END WHILE;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `generate_transaksi_advanced` ()   BEGIN
  DECLARE i INT DEFAULT 1;
  DECLARE random_pembeli INT;
  DECLARE random_produk INT;
  DECLARE jumlah_item INT;
  DECLARE harga_produk DECIMAL(12,2);
  DECLARE subtotal_item DECIMAL(12,2);
  DECLARE total_transaksi DECIMAL(12,2);
  DECLARE item_count INT;

  WHILE i <= 5000 DO

    SET random_pembeli = FLOOR(1 + RAND()*5000);
    SET total_transaksi = 0;

      id_pembeli,id_alamat,total_harga,status_pesanan,kode_invoice
    ) VALUES (
      random_pembeli,
      random_pembeli,
      0,
      ELT(FLOOR(1+RAND()*4),'pending','diproses','dikirim','selesai'),
      CONCAT('INV2026',i)
    );

    SET item_count = FLOOR(1 + RAND()*3);

    WHILE item_count > 0 DO

      SET random_produk = FLOOR(1 + RAND()*15);
      SET jumlah_item = FLOOR(1 + RAND()*3);

      SELECT harga INTO harga_produk FROM Produk WHERE id_produk = random_produk;

      SET subtotal_item = harga_produk * jumlah_item;
      SET total_transaksi = total_transaksi + subtotal_item;

        id_pesanan,id_produk,jumlah,harga_satuan,subtotal
      ) VALUES (
        i,random_produk,jumlah_item,harga_produk,subtotal_item
      );

      SET item_count = item_count - 1;
    END WHILE;

    UPDATE Pesanan SET total_harga = total_transaksi WHERE id_pesanan = i;

      id_pesanan,id_metode,jumlah_bayar,status_pembayaran
    ) VALUES (
      i,1,total_transaksi,
      ELT(FLOOR(1+RAND()*3),'pending','lunas','gagal')
    );

      id_pesanan,id_produk,id_pembeli,rating,komentar
    ) VALUES (
      i,
      FLOOR(1 + RAND()*15),
      random_pembeli,
      FLOOR(3 + RAND()*3),
      ELT(FLOOR(1+RAND()*5),'Barang bagus dan original','Packing rapi','Pengiriman cepat','Sesuai deskripsi','Recommended seller')
    );

    SET i = i + 1;
  END WHILE;
END$$

