--
-- Structure for view `view_customer_activity`
--
DROP TABLE IF EXISTS `view_customer_activity`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `view_customer_activity`  AS SELECT `p`.`nama_pembeli` AS `nama_user`, count(`o`.`id_pesanan`) AS `total_order`, sum(`dp`.`subtotal`) AS `total_spending` FROM ((`pembeli` `p` join `pesanan` `o` on(`p`.`id_pembeli` = `o`.`id_pembeli`)) join `detail_pesanan` `dp` on(`o`.`id_pesanan` = `dp`.`id_pesanan`)) WHERE `o`.`status_pesanan` = 'selesai' GROUP BY `p`.`id_pembeli` ;

-- --------------------------------------------------------

--
-- Structure for view `view_order_summary`
--
DROP TABLE IF EXISTS `view_order_summary`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `view_order_summary`  AS SELECT `o`.`id_pesanan` AS `order_id`, `p`.`nama_pembeli` AS `nama_user`, sum(`dp`.`jumlah`) AS `total_item`, sum(`dp`.`subtotal`) AS `total_harga`, `o`.`status_pesanan` AS `status`, `o`.`tanggal_pesanan` AS `tanggal_order` FROM ((`pesanan` `o` join `pembeli` `p` on(`o`.`id_pembeli` = `p`.`id_pembeli`)) join `detail_pesanan` `dp` on(`o`.`id_pesanan` = `dp`.`id_pesanan`)) GROUP BY `o`.`id_pesanan` ;

-- --------------------------------------------------------

--
-- Structure for view `view_product_sales`
--
DROP TABLE IF EXISTS `view_product_sales`;

CREATE ALGORITHM=UNDEFINED DEFINER=`root`@`localhost` SQL SECURITY DEFINER VIEW `view_product_sales`  AS SELECT `pr`.`nama_produk` AS `product_name`, sum(`dp`.`jumlah`) AS `total_terjual`, sum(`dp`.`subtotal`) AS `total_pendapatan` FROM ((`produk` `pr` join `detail_pesanan` `dp` on(`pr`.`id_produk` = `dp`.`id_produk`)) join `pesanan` `o` on(`dp`.`id_pesanan` = `o`.`id_pesanan`)) WHERE `o`.`status_pesanan` = 'selesai' GROUP BY `pr`.`id_produk` ;

